-- ---------------------------------------------------------- Tabel structuur voor tabel cadeautjetabel-- --------------------------------------------------------DROP TABLE IF EXISTS cadeautjetabel;CREATE TABLE cadeautjetabel (cadeau_id smallint(8) NOT NULL auto_increment,-- persoon_id smallint(11) NOT NULL default '',anoniem smallint(3) default '0',gever_voornaam varchar(20) NOT NULL default 'voornaam',gever_achternaam varchar(30) NOT NULL default 'achternaam',gever_emailadres varchar(37) NOT NULL default '',ontvang_voornaam varchar(20) NOT NULL default 'voornaam',ontvang_achternaam varchar(30) NOT NULL default 'achternaam',ontvang_emailadres varchar(37) NOT NULL default '',gever_remote_addr varchar(20) NOT NULL default '',gever_confirm_hash varchar(50) NOT NULL default '',gever_is_confirmed smallint(4) default NULL,gever_date_created date default NULL,PRIMARY KEY (cadeau_id),KEY gever_emailadres (gever_emailadres),KEY ontvang_emailadres (ontvang_emailadres)) TYPE=MyISAM AUTO_INCREMENT=99 ;-- Gegevens worden uitgevoerd voor tabel cadeautjetabelINSERT INTO cadeautjetabel VALUES (1, 0, 'voornaam', 'achternaam', 'info@helpdisk.nl', 'voornaam', 'achternaam', 'info@helpdisk.nl', '10.10.10', '0101010', '', '2006-01-01');